using Lumeo.Services.Localization;

namespace Lumeo;

/// <summary>
/// A single AI action that operates on the current editor selection.
/// </summary>
public sealed record AiAction(string Id, string Label, string? IconName = null);

/// <summary>Built-in AI actions surfaced by the bubble menu / AiActionMenu.</summary>
public static class AiActions
{
    // EN fallback IDs — kept so existing code that references AiActions.Improve etc.
    // still works. The labels here are the English defaults; use LocalizedDefault to
    // get locale-aware labels at render time.
    public static AiAction Improve { get; } = new("improve", "Improve writing", "Sparkles");
    public static AiAction Shorten { get; } = new("shorten", "Make shorter", "Minimize2");
    public static AiAction Expand { get; } = new("expand", "Make longer", "Maximize2");
    public static AiAction Translate { get; } = new("translate", "Translate", "Languages");
    public static AiAction Summarize { get; } = new("summarize", "Summarize", "FileText");
    public static AiAction FixGrammar { get; } = new("fix-grammar", "Fix grammar", "SpellCheck");

    /// <summary>Default action set with EN labels. Prefer <see cref="LocalizedDefault"/> when a
    /// localizer is available so labels reflect the active locale.</summary>
    public static IReadOnlyList<AiAction> Default { get; } = new[]
    {
        Improve, Shorten, Expand, FixGrammar, Summarize, Translate,
    };

    /// <summary>Returns the default action set with labels resolved through the active localizer.</summary>
    public static IReadOnlyList<AiAction> LocalizedDefault(ILumeoLocalizer L) => new[]
    {
        new AiAction("improve",    L["Editor.AiImproveWriting"], "Sparkles"),
        new AiAction("shorten",    L["Editor.AiMakeShorter"],   "Minimize2"),
        new AiAction("expand",     L["Editor.AiMakeLonger"],    "Maximize2"),
        new AiAction("fix-grammar",L["Editor.AiFixGrammar"],    "SpellCheck"),
        new AiAction("summarize",  L["Editor.AiSummarize"],     "FileText"),
        new AiAction("translate",  L["Editor.AiTranslate"],     "Languages"),
    };
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@*
    Floating list of AI actions (Improve / Shorten / Expand / ...). Wired to
    the editor's selection — picking an item fires OnAction with the action
    record and the editor's currently selected text; consumer returns the
    replacement HTML, which the editor inserts via executeCommand("replaceSelection").
*@

<div class="@RootClass" role="menu" aria-label="@L["Editor.AiActions"]" @attributes="AdditionalAttributes">
    @foreach (var action in EffectiveActions)
    {
        var a = action;
        <button type="button"
                role="menuitem"
                class="flex w-full items-center gap-2 px-2.5 py-1.5 rounded-md text-sm hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground focus:outline-none"
                @onmousedown:preventDefault="true"
                @onclick="() => OnAction.InvokeAsync(a)">
            @if (!string.IsNullOrEmpty(a.IconName))
            {
                <span class="text-muted-foreground"><Icon Name="@a.IconName" Size="Lumeo.Size.Sm" /></span>
            }
            <span class="flex-1 text-left">@a.Label</span>
        </button>
    }
</div>

@code {
    [Parameter] public IReadOnlyList<AiAction>? Actions { get; set; }
    [Parameter] public EventCallback<AiAction> OnAction { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private IReadOnlyList<AiAction> EffectiveActions => Actions ?? AiActions.LocalizedDefault(L);

    private string RootClass =>
        $"min-w-[200px] rounded-lg border border-border/60 bg-popover text-popover-foreground shadow-lg p-1 {Class}".Trim();
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@*
    Static (non-floating) bubble-menu primitive consumers can drop into a
    custom toolbar. The live floating bubble menu is rendered in JS by the
    editor itself when EnableBubbleMenu=true on RichTextEditor. This component
    exists so consumers can also build their own selection menu out of band.
*@

<div class="@RootClass" role="toolbar" aria-label="@L["Editor.FormatSelection"]" @attributes="AdditionalAttributes">
    <button type="button" class="@BtnClass" title="@L["Editor.Bold"]" aria-label="@L["Editor.Bold"]"
            @onmousedown:preventDefault="true" @onclick="@(() => OnCommand.InvokeAsync("bold"))">
        <Icon Name="Bold" Size="Lumeo.Size.Sm" />
    </button>
    <button type="button" class="@BtnClass" title="@L["Editor.Italic"]" aria-label="@L["Editor.Italic"]"
            @onmousedown:preventDefault="true" @onclick="@(() => OnCommand.InvokeAsync("italic"))">
        <Icon Name="Italic" Size="Lumeo.Size.Sm" />
    </button>
    <button type="button" class="@BtnClass" title="@L["Editor.Underline"]" aria-label="@L["Editor.Underline"]"
            @onmousedown:preventDefault="true" @onclick="@(() => OnCommand.InvokeAsync("underline"))">
        <Icon Name="Underline" Size="Lumeo.Size.Sm" />
    </button>
    <button type="button" class="@BtnClass" title="@L["Editor.Link"]" aria-label="@L["Editor.Link"]"
            @onmousedown:preventDefault="true" @onclick="@(() => OnCommand.InvokeAsync("link"))">
        <Icon Name="Link" Size="Lumeo.Size.Sm" />
    </button>
    @if (EnableAiActions)
    {
        <button type="button" class="@BtnClass" title="@L["Editor.AiActions"]" aria-label="@L["Editor.AiActions"]"
                @onmousedown:preventDefault="true" @onclick="@(() => OnAiMenuToggled.InvokeAsync())">
            <Icon Name="Sparkles" Size="Lumeo.Size.Sm" />
        </button>
    }
</div>

@code {
    [Parameter] public bool EnableAiActions { get; set; }
    [Parameter] public EventCallback<string> OnCommand { get; set; }
    [Parameter] public EventCallback OnAiMenuToggled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string RootClass =>
        $"inline-flex items-center gap-0.5 rounded-lg border border-border/60 bg-popover text-popover-foreground shadow-md p-1 {Class}".Trim();

    private const string BtnClass =
        "inline-flex h-7 w-7 items-center justify-center rounded-md text-muted-foreground transition-colors hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1";
}

namespace Lumeo;

/// <summary>
/// Metadata about an image the user dropped, pasted, or picked through the
/// editor's image button. Returned to consumers via
/// <see cref="RichTextEditor.OnImageRequested"/>; consumer is responsible for
/// uploading the actual bytes (typically via a paired <c>InputFile</c>) and
/// returning a final URL.
/// </summary>
public sealed record EditorImageRequest(string FileName, string MimeType, long Size);

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@*
    Preset-driven toolbar rendered above the editor surface. Each button
    invokes OnCommand which the parent RichTextEditor forwards to the JS
    editor via executeCommand.
*@

<div class="@RootClass" role="toolbar" aria-label="@L["Editor.ToolbarAriaLabel"]" @attributes="AdditionalAttributes">
    @if (Preset == EditorToolbarPreset.Full)
    {
        @Btn(L["Editor.Paragraph"], "Pilcrow", "setParagraph", Active?.Paragraph == true)
        @Btn(L["Editor.Heading1"], "Heading1", "setHeading", Active?.Heading1 == true, 1)
        @Btn(L["Editor.Heading2"], "Heading2", "setHeading", Active?.Heading2 == true, 2)
        @Btn(L["Editor.Heading3"], "Heading3", "setHeading", Active?.Heading3 == true, 3)
        @Sep()
    }
    else if (Preset == EditorToolbarPreset.Standard)
    {
        @Btn(L["Editor.Heading1"], "Heading1", "setHeading", Active?.Heading1 == true, 1)
        @Btn(L["Editor.Heading2"], "Heading2", "setHeading", Active?.Heading2 == true, 2)
        @Sep()
    }

    @Btn(L["Editor.Bold"], "Bold", "bold", Active?.Bold == true)
    @Btn(L["Editor.Italic"], "Italic", "italic", Active?.Italic == true)

    @if (Preset != EditorToolbarPreset.Minimal)
    {
        @Btn(L["Editor.Underline"], "Underline", "underline", Active?.Underline == true)
        @Btn(L["Editor.Strikethrough"], "Strikethrough", "strike", Active?.Strike == true)
    }

    @if (Preset == EditorToolbarPreset.Full)
    {
        @Btn(L["Editor.InlineCode"], "Code", "code", Active?.Code == true)
    }

    @if (Preset != EditorToolbarPreset.Minimal)
    {
        @Sep()
        @Btn(L["Editor.BulletList"], "List", "bulletList", Active?.BulletList == true)
        @Btn(L["Editor.NumberedList"], "ListOrdered", "orderedList", Active?.OrderedList == true)

        @if (Preset == EditorToolbarPreset.Full)
        {
            @Btn(L["Editor.TaskList"], "ListChecks", "taskList", false)
            @Sep()
            @Btn(L["Editor.Quote"], "Quote", "blockquote", Active?.Blockquote == true)
            @Btn(L["Editor.CodeBlock"], "SquareCode", "codeBlock", Active?.CodeBlock == true)
            @Btn(L["Editor.HorizontalRule"], "Minus", "hr", false)
        }
    }

    @Sep()
    @Btn(L["Editor.Link"], "Link", "link", Active?.Link == true)
    @if (Preset != EditorToolbarPreset.Minimal)
    {
        @Btn(L["Editor.Unlink"], "Unlink", "unlink", false, disabled: Active?.Link != true)
    }

    @if (Preset == EditorToolbarPreset.Full)
    {
        @Sep()
        @Btn(L["Editor.InsertTable"], "Table", "insertTable", false)
        @Btn(L["Editor.InsertImage"], "Image", "pickImage", false)
        @if (AllowWordImport)
        {
            @Btn(L["Editor.ImportDocx"], "FileText", "pickWord", false)
        }
        @if (EnableAiActions)
        {
            @Btn(L["Editor.AiActions"], "Sparkles", "ai-menu", false)
        }
    }

    @Sep()
    @Btn(L["Editor.Undo"], "Undo", "undo", false, disabled: Active?.CanUndo == false)
    @Btn(L["Editor.Redo"], "Redo", "redo", false, disabled: Active?.CanRedo == false)

    @if (Preset == EditorToolbarPreset.Full)
    {
        @Btn(L["Editor.ClearFormatting"], "RemoveFormatting", "clearFormat", false)
    }
</div>

@code {
    [Parameter] public EditorToolbarPreset Preset { get; set; } = EditorToolbarPreset.Standard;
    [Parameter] public Lumeo.Services.Interop.RichTextActiveState? Active { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public bool AllowWordImport { get; set; }
    [Parameter] public bool EnableAiActions { get; set; }
    [Parameter] public EventCallback<(string command, object? arg)> OnCommand { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string RootClass =>
        $"flex flex-wrap items-center gap-0.5 border-b border-border/40 bg-muted/30 px-2 py-1.5 {Class}".Trim();

    private RenderFragment Sep() => builder =>
    {
        builder.OpenElement(0, "span");
        builder.AddAttribute(1, "aria-hidden", "true");
        builder.AddAttribute(2, "class", "mx-0.5 h-5 w-px bg-border");
        builder.CloseElement();
    };

    private RenderFragment Btn(string label, string icon, string command, bool active, object? arg = null, bool disabled = false)
        => builder =>
        {
            var isDisabled = disabled || Disabled;
            var cls = active
                ? "inline-flex h-7 w-7 items-center justify-center rounded-md bg-accent text-accent-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                : "inline-flex h-7 w-7 items-center justify-center rounded-md text-muted-foreground transition-colors hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1";
            if (isDisabled) cls += " opacity-50 cursor-not-allowed";

            builder.OpenElement(0, "button");
            builder.AddAttribute(1, "type", "button");
            builder.AddAttribute(2, "class", cls);
            builder.AddAttribute(3, "title", label);
            builder.AddAttribute(4, "aria-label", label);
            builder.AddAttribute(5, "aria-pressed", active ? "true" : "false");
            if (isDisabled)
            {
                builder.AddAttribute(6, "disabled", true);
            }
            else
            {
                builder.AddAttribute(7, "onclick",
                    Microsoft.AspNetCore.Components.EventCallback.Factory.Create(
                        this, async () => await OnCommand.InvokeAsync((command, arg))));
                builder.AddAttribute(8, "onmousedown", "event.preventDefault()");
            }
            builder.OpenComponent<Icon>(9);
            builder.AddAttribute(10, "Name", icon);
            builder.AddAttribute(11, "Size", Lumeo.Size.Sm);
            builder.CloseComponent();
            builder.CloseElement();
        };
}

namespace Lumeo;

/// <summary>
/// Toolbar density presets for <see cref="RichTextEditor"/>.
/// </summary>
public enum EditorToolbarPreset
{
    /// <summary>No toolbar at all (consumer-driven via context menu / keyboard).</summary>
    None,
    /// <summary>Bold, Italic, Link only.</summary>
    Minimal,
    /// <summary>Headings, basic marks, lists, link, undo/redo. Default.</summary>
    Standard,
    /// <summary>Standard plus tables, image, code block, AI menu, Word import.</summary>
    Full,
}

using Microsoft.AspNetCore.Components;

namespace Lumeo;

/// <summary>
/// Registers a typed trigger character (`@`, `#`, `$`, `/`, ...) on the
/// <see cref="RichTextEditor"/>. When the user types the character, the
/// editor calls <see cref="ItemSource"/> with the partial query and renders
/// a floating result list.
/// </summary>
public sealed record EditorTrigger(
    char Char,
    Func<string, ValueTask<IReadOnlyList<TriggerItem>>> ItemSource,
    RenderFragment<TriggerItem>? ItemTemplate = null,
    string? ChipClass = null);

/// <summary>
/// A single row shown in the trigger or slash-command dropdown. Lightweight
/// enough that result lists can be returned from arbitrary backends without
/// allocating UI types.
/// </summary>
public sealed record TriggerItem(
    string Id,
    string Label,
    string? Subtitle = null,
    string? IconName = null,
    object? Payload = null);

@namespace Lumeo
@inject Services.ComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L
@implements IAsyncDisposable

@if (_initError is not null)
{
    <div class="rounded-lg border border-destructive/30 bg-destructive/10 p-4 text-sm text-destructive">Editor failed to initialize: @_initError</div>
}
else
{

@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium text-foreground mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ml-0.5">*</span>
        }
    </label>
}

<div class="@RootClass" @attributes="AdditionalAttributes" aria-required="@(Required ? "true" : "false")" aria-invalid="@(EffectiveInvalid ? "true" : "false")">
    @if (EffectiveToolbar != EditorToolbarPreset.None)
    {
        <EditorToolbar Preset="EffectiveToolbar"
                       Active="_active"
                       Disabled="Disabled || ReadOnly"
                       AllowWordImport="AllowWordImport"
                       EnableAiActions="EnableAiActions"
                       OnCommand="HandleToolbarCommand" />
    }

    <div @ref="_contentRef" style="@ContentStyle" class="lumeo-rte-content bg-card"></div>
</div>

@if (!InsideFormField)
{
    @if (_wordImportError is not null)
    {
        <p class="text-xs text-destructive mt-1.5" role="alert">@_wordImportError</p>
    }
    else if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive mt-1.5">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground mt-1.5">@HelperText</p>
    }
}

<Dialog @bind-Open="_linkDialogOpen">
    <DialogContent Class="max-w-md">
        <DialogHeader>
            <DialogTitle>@L["Editor.InsertLinkTitle"]</DialogTitle>
            <DialogDescription>@L["Editor.InsertLinkDescription"]</DialogDescription>
        </DialogHeader>
        <div class="py-2">
            <Input @bind-Value="_linkDialogUrl"
                   Placeholder="https://"
                   @onkeydown="HandleLinkDialogKey" />
        </div>
        <DialogFooter>
            <Button Variant="Button.ButtonVariant.Outline" OnClick="CancelLinkDialog">@L["Editor.Cancel"]</Button>
            <Button Variant="Button.ButtonVariant.Default" OnClick="ApplyLinkDialog" Disabled="@string.IsNullOrWhiteSpace(_linkDialogUrl)">
                @L["Editor.Apply"]
            </Button>
        </DialogFooter>
    </DialogContent>
</Dialog>

} @* end @if (_initError is not null) else *@

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    // ---- Backwards-compatible params ----
    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string?> ValueChanged { get; set; }
    [Parameter] public string? Placeholder { get; set; }
    private string EffectivePlaceholder => Placeholder ?? L["Editor.StartWriting"];
    [Parameter] public int MinHeight { get; set; } = 180;
    [Parameter] public int? MaxHeight { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public bool ReadOnly { get; set; }
    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }

    /// <summary>Legacy toolbar mode; superseded by <see cref="Toolbar"/>.</summary>
    [Parameter] public RichTextToolbarMode? ToolbarMode { get; set; }

    /// <summary>Toolbar density preset. Defaults to <see cref="EditorToolbarPreset.Standard"/>.</summary>
    [Parameter] public EditorToolbarPreset Toolbar { get; set; } = EditorToolbarPreset.Standard;

    // ---- New: rich features ----
    [Parameter] public IReadOnlyList<EditorTrigger>? Triggers { get; set; }
    [Parameter] public bool EnableSlashCommand { get; set; } = true;
    [Parameter] public bool EnableTables { get; set; } = true;
    [Parameter] public bool EnableCodeBlock { get; set; } = true;
    [Parameter] public bool EnableImages { get; set; } = true;
    [Parameter] public bool EnableTaskList { get; set; } = true;
    [Parameter] public bool EnableMarkdownShortcuts { get; set; } = true;
    [Parameter] public bool EnableAiActions { get; set; }
    [Parameter] public bool EnableBubbleMenu { get; set; } = true;
    [Parameter] public bool EnableDragHandle { get; set; } = true;
    [Parameter] public int? MaxLength { get; set; }
    [Parameter] public bool AllowWordImport { get; set; }

    /// <summary>
    /// Maximum size, in bytes, of a Word document accepted by the in-browser import path.
    /// Defaults to 8 MB. Larger files are refused before being read into memory and surfaced
    /// to the user via <see cref="WordImportError"/>. Set explicitly when consumers expect
    /// large documents and the deployment can afford the memory.
    /// </summary>
    [Parameter] public long MaxWordImportBytes { get; set; } = 8L * 1024L * 1024L;

    /// <summary>Resolves a picked image into a URL (or data URI). Receives file metadata
    /// from JS; consumer is expected to upload the file out-of-band (e.g. via a paired
    /// <c>InputFile</c>) and return a final URL. If null, images fall back to base64.</summary>
    [Parameter] public Func<EditorImageRequest, ValueTask<string?>>? OnImageRequested { get; set; }

    /// <summary>Selection-driven AI actions. Receives the action id and selected plain text;
    /// returns replacement HTML to be inserted in place of the selection.</summary>
    [Parameter] public Func<string, string, ValueTask<string?>>? OnAiAction { get; set; }

    /// <summary>Optional override for Word import. Receives the picked file payload
    /// (filename + bytes) and returns HTML to replace the editor content. When NOT set,
    /// the file is converted in-browser via <see cref="WordImporter"/> (Mammoth runs
    /// inside the WASM bundle), so the demo works on static hosting with no server.
    /// Set this when you want server-side conversion (better fidelity for complex docs).</summary>
    [Parameter] public Func<WordImportPayload, ValueTask<string>>? OnWordImportRequested { get; set; }

    [Parameter] public EventCallback<string> OnInitError { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    private EditorToolbarPreset EffectiveToolbar => ToolbarMode switch
    {
        RichTextToolbarMode.None => EditorToolbarPreset.None,
        RichTextToolbarMode.Basic => EditorToolbarPreset.Minimal,
        RichTextToolbarMode.Full => EditorToolbarPreset.Full,
        _ => Toolbar,
    };

    private Microsoft.AspNetCore.Components.ElementReference _contentRef;
    private DotNetObjectReference<RichTextEditor>? _selfRef;
    private string? _instanceId;
    private string? _lastSetValue;
    private bool _lastDisabled;
    private bool _lastReadOnly;
    private Services.Interop.RichTextActiveState? _active;
    private bool _initialized;
    private string? _initError;

    // Link dialog state (replaces the native browser prompt for the toolbar
    // and bubble menu's Link button).
    private bool _linkDialogOpen;
    private string _linkDialogUrl = string.Empty;

    // Surface the most-recent Word import failure (size cap, decode error, etc.)
    // inline below the editor — same slot the EffectiveInvalid path uses.
    private string? _wordImportError;

    private void OpenLinkDialog(string? initial)
    {
        _linkDialogUrl = string.IsNullOrWhiteSpace(initial) ? "https://" : initial;
        _linkDialogOpen = true;
        StateHasChanged();
    }

    private void CancelLinkDialog()
    {
        _linkDialogOpen = false;
    }

    private async Task ApplyLinkDialog()
    {
        var url = _linkDialogUrl?.Trim();
        _linkDialogOpen = false;
        if (string.IsNullOrWhiteSpace(url) || _instanceId is null) return;
        await Interop.RichTextCommandAsync(_instanceId, "link", new object?[] { url });
    }

    private async Task HandleLinkDialogKey(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await ApplyLinkDialog();
        else if (e.Key == "Escape") CancelLinkDialog();
    }

    [JSInvokable("OnLinkRequested")]
    public Task OnLinkRequestedJs(string? currentUrl)
    {
        OpenLinkDialog(currentUrl);
        return Task.CompletedTask;
    }

    private string RootClass =>
        $"rounded-lg border {(EffectiveInvalid ? "border-destructive focus-within:ring-destructive/20" : "border-border/40 focus-within:border-ring/60 focus-within:ring-ring/40")} bg-card overflow-hidden transition-colors focus-within:ring-[1.5px] {Class}".Trim();

    private string ContentStyle
    {
        get
        {
            var parts = new List<string> { $"min-height: {MinHeight}px" };
            if (MaxHeight is int max)
            {
                parts.Add($"max-height: {max}px");
                parts.Add("overflow-y: auto");
            }
            return string.Join("; ", parts) + ";";
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _selfRef = DotNetObjectReference.Create(this);
            _lastSetValue = Value;
            _lastDisabled = Disabled;
            _lastReadOnly = ReadOnly;

            // Build the "trigger" descriptor list passed into JS — only the
            // metadata the JS needs (char + label). Item resolution happens via
            // the OnTriggerQuery JSInvokable below, which fans queries out to
            // the matching EditorTrigger registered server-side.
            var triggerMeta = (Triggers ?? Array.Empty<EditorTrigger>())
                .Select(t => new { @char = t.Char.ToString(), label = $"{t.Char} suggestions" })
                .ToArray();

            var options = new
            {
                content = Value ?? string.Empty,
                initialHtml = Value ?? string.Empty,
                placeholder = EffectivePlaceholder,
                disabled = Disabled,
                readOnly = ReadOnly,
                editable = !Disabled && !ReadOnly,
                mentionTriggers = triggerMeta,
                enableSlashCommand = EnableSlashCommand,
                enableTables = EnableTables,
                enableCodeBlock = EnableCodeBlock,
                enableImages = EnableImages,
                enableTaskList = EnableTaskList,
                enableMarkdownShortcuts = EnableMarkdownShortcuts,
                enableAiActions = EnableAiActions,
                enableBubbleMenu = EnableBubbleMenu,
                enableDragHandle = EnableDragHandle,
                maxLength = MaxLength,
                maxWordImportBytes = MaxWordImportBytes,
            };

            try
            {
                _instanceId = await Interop.RichTextInitAsync(_contentRef, _selfRef, options);
            }
            catch (JSException ex)
            {
                _initError = ex.Message;
                Console.Error.WriteLine($"[Lumeo RichTextEditor] Init failed: {ex.Message}");
                if (OnInitError.HasDelegate)
                    await OnInitError.InvokeAsync(ex.Message);
                StateHasChanged();
                return;
            }
            _initialized = !string.IsNullOrEmpty(_instanceId);
            if (_initialized)
            {
                await RefreshActiveAsync();
            }
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        if (!_initialized || _instanceId is null) return;

        if (!string.Equals(Value, _lastSetValue, StringComparison.Ordinal))
        {
            _lastSetValue = Value;
            await Interop.RichTextSetContentAsync(_instanceId, Value);
        }

        if (Disabled != _lastDisabled || ReadOnly != _lastReadOnly)
        {
            _lastDisabled = Disabled;
            _lastReadOnly = ReadOnly;
            await Interop.RichTextSetDisabledAsync(_instanceId, Disabled || ReadOnly);
        }
    }

    // ---------------- JS callbacks ----------------

    [JSInvokable]
    public async Task OnContentUpdate(string html)
    {
        _lastSetValue = html;
        Value = html;
        await ValueChanged.InvokeAsync(html);
        await RefreshActiveAsync();
    }

    /// <summary>Mirror of <see cref="OnContentUpdate"/> kept for the new JS naming.</summary>
    [JSInvokable]
    public Task OnUpdate(string html) => OnContentUpdate(html);

    [JSInvokable]
    public Task OnSelectionUpdate() => RefreshActiveAsync();

    [JSInvokable]
    public async Task<IReadOnlyList<TriggerItem>> OnTriggerQuery(string triggerChar, string query)
    {
        // Slash command default — only kicks in if no consumer trigger overrides '/'.
        if (triggerChar == "/" && (Triggers is null || !Triggers.Any(t => t.Char == '/')))
        {
            return EnableSlashCommand
                ? await SlashCommands.Filter(query, L)
                : Array.Empty<TriggerItem>();
        }

        var trigger = Triggers?.FirstOrDefault(t => t.Char.ToString() == triggerChar);
        if (trigger is null) return Array.Empty<TriggerItem>();
        try
        {
            return await trigger.ItemSource(query) ?? Array.Empty<TriggerItem>();
        }
        catch
        {
            return Array.Empty<TriggerItem>();
        }
    }

    [JSInvokable("OnImageRequested")]
    public async Task<string?> OnImageRequestedJs(string fileName, string mimeType, long size)
    {
        if (OnImageRequested is null) return null;
        try
        {
            return await OnImageRequested(new EditorImageRequest(fileName, mimeType, size));
        }
        catch
        {
            return null;
        }
    }

    [JSInvokable("OnAiAction")]
    public async Task<string?> OnAiActionJs(string actionId, string selectedText)
    {
        if (OnAiAction is null) return null;
        try
        {
            return await OnAiAction(actionId, selectedText);
        }
        catch
        {
            return null;
        }
    }

    [JSInvokable("OnWordImportRequested")]
    public async Task OnWordImportRequestedJs(string fileName, string base64Content)
    {
        try
        {
            // Pre-allocation size guard — decoded length is computed from the base64
            // string length, so an oversized payload is rejected BEFORE the .NET
            // byte[] allocation that would normally double peak memory usage.
            var bytes = WordImporter.DecodeBase64WithLimit(base64Content, MaxWordImportBytes);
            var payload = new WordImportPayload(fileName, bytes);

            string html;
            if (OnWordImportRequested is not null)
            {
                html = await OnWordImportRequested(payload);
            }
            else
            {
                using var stream = new MemoryStream(bytes);
                var result = await WordImporter.ToHtmlAsync(stream);
                html = result.Html;
            }

            if (!string.IsNullOrEmpty(html))
            {
                _wordImportError = null;
                await SetHtmlAsync(html);
            }
        }
        catch (WordImportSizeException sizeEx)
        {
            _wordImportError = $"Word document too large ({FormatBytes(sizeEx.ActualBytes)}). Limit is {FormatBytes(sizeEx.LimitBytes)}.";
            StateHasChanged();
        }
        catch (Exception ex)
        {
            _wordImportError = "Word import failed. Try saving the document again or pick a different file.";
            Console.Error.WriteLine($"Word import failed: {ex.Message}");
            StateHasChanged();
        }
    }

    [JSInvokable("OnWordImportFailed")]
    public Task OnWordImportFailedJs(string reason, long size, long limit)
    {
        _wordImportError = reason switch
        {
            "file_too_large" => $"Word document too large ({FormatBytes(size)}). Limit is {FormatBytes(limit)}.",
            _ => "Word import failed. Try saving the document again or pick a different file.",
        };
        StateHasChanged();
        return Task.CompletedTask;
    }

    private static string FormatBytes(long bytes)
    {
        if (bytes < 1024) return $"{bytes} B";
        if (bytes < 1024 * 1024) return $"{bytes / 1024.0:0.#} KB";
        return $"{bytes / (1024.0 * 1024.0):0.#} MB";
    }

    // ---------------- Toolbar dispatch ----------------

    private async Task HandleToolbarCommand((string command, object? arg) cmd)
    {
        if (_instanceId is null || Disabled || ReadOnly) return;

        switch (cmd.command)
        {
            case "link":
            {
                OpenLinkDialog(null);
                break;
            }
            case "ai-menu":
                // Reserved for a future popover. For now, fire an "improve" against
                // current selection if the consumer wired OnAiAction.
                if (OnAiAction is not null)
                {
                    await Interop.RichTextCommandAsync(_instanceId, "noop", null);
                }
                break;
            default:
                var args = cmd.arg is null ? null : new object?[] { cmd.arg };
                await Interop.RichTextCommandAsync(_instanceId, cmd.command, args);
                break;
        }

        await RefreshActiveAsync();
    }

    private async Task RefreshActiveAsync()
    {
        if (_instanceId is null) return;
        _active = await Interop.RichTextGetActiveAsync(_instanceId);
        StateHasChanged();
    }

    // ---------------- Public API for consumers ----------------

    /// <summary>Replaces the editor content with the given HTML.</summary>
    public async ValueTask SetHtmlAsync(string? html)
    {
        if (_instanceId is null) return;
        _lastSetValue = html;
        Value = html;
        await Interop.RichTextSetContentAsync(_instanceId, html);
        await ValueChanged.InvokeAsync(html);
    }

    public async ValueTask DisposeAsync()
    {
        if (_instanceId is not null)
        {
            try
            {
                await Interop.RichTextDestroyAsync(_instanceId);
            }
            catch (JSDisconnectedException) { /* ignore — circuit already gone */ }
            _instanceId = null;
        }
        _selfRef?.Dispose();
        _selfRef = null;
    }

    /// <summary>Legacy toolbar mode — kept so existing call sites compile.</summary>
    public enum RichTextToolbarMode
    {
        None,
        Basic,
        Full,
    }
}

