<div class="@RootClass" role="listbox" aria-label="@EffectiveAriaLabel" id="@Id" @attributes="AdditionalAttributes">
    @if (Items is null || Items.Count == 0)
    {
        <div class="px-2.5 py-2 text-xs text-muted-foreground">@L["Editor.NoResults"]</div>
    }
    else
    {
        @for (var i = 0; i < Items.Count; i++)
        {
