            var rowClass = selected
                ? "flex items-start gap-2 px-2.5 py-1.5 rounded-md cursor-pointer bg-accent text-accent-foreground"
                : "flex items-start gap-2 px-2.5 py-1.5 rounded-md cursor-pointer hover:bg-accent/60";

